<?php
declare(strict_types=1);require_once __DIR__.'/_layout.php';require_once dirname(__DIR__,2).'/includes/comunicaciones.php';require_once dirname(__DIR__,2).'/includes/mailer.php';require_once dirname(__DIR__,2).'/includes/errores_sistema.php';require_once dirname(__DIR__,2).'/includes/audit.php';exigirPermiso('academic.communications.send');if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf((string)($_POST['csrf_token']??''))){http_response_code(400);exit;}$pdo=obtenerConexion();$docenteId=docenteSupervisadoAtenea($pdo);$curso=docenteId($_POST['asignatura_id']??0);$estudiante=docenteId($_POST['estudiante_id']??0);$asunto=trim(strip_tags((string)($_POST['asunto']??'')));$mensaje=textoComunicacionAtenea((string)($_POST['mensaje']??''));try{exigirCursoDocente($pdo,$docenteId,$curso);if(!docentePuedeEstudiante($pdo,$docenteId,$estudiante,$curso))throw new DomainException('El estudiante no pertenece a este curso.');if($asunto===''||mb_strlen($asunto)>190||preg_match('/[\r\n]/',$asunto)||$mensaje==='')throw new DomainException('Revisa el asunto y mensaje.');$q=$pdo->prepare('SELECT nombre,apellido,correo FROM usuarios WHERE id=:id AND rol=\'usuario\' AND estado=\'activo\'');$q->execute(['id'=>$estudiante]);$u=$q->fetch();if(!$u)throw new DomainException('El estudiante no está disponible.');$pdo->beginTransaction();$pdo->prepare("INSERT INTO comunicacion_hilos(canal,asunto,usuario_id,nombre_contacto,correo_contacto,asignatura_id,docente_id,estado,ultimo_mensaje_at) VALUES('plataforma',:a,:u,:n,:c,:asig,:d,'respondido',NOW())")->execute(['a'=>$asunto,'u'=>$estudiante,'n'=>trim($u['nombre'].' '.$u['apellido']),'c'=>$u['correo'],'asig'=>$curso,'d'=>$docenteId]);$hilo=(int)$pdo->lastInsertId();$pdo->prepare("INSERT INTO comunicacion_mensajes(hilo_id,direccion,autor_usuario_id,autor_nombre,autor_correo,contenido,resultado_envio) VALUES(:h,'salida',:u,'Docente Atenea',NULL,:m,'pendiente')")->execute(['h'=>$hilo,'u'=>$_SESSION['usuario_id'],'m'=>$mensaje]);$mid=(int)$pdo->lastInsertId();crearNotificacionAtenea(['usuario_id'=>$estudiante,'created_by'=>$_SESSION['usuario_id'],'tipo'=>'mensaje_docente','categoria'=>'academico','nivel'=>'informacion','titulo'=>$asunto,'descripcion'=>mb_substr($mensaje,0,300),'url'=>atenea_url('src/estudiantes/index.php'),'hilo_id'=>$hilo,'idempotency_key'=>'academico:hilo:'.$hilo],$pdo);registrarAuditoria(['actor_user_id'=>$_SESSION['usuario_id'],'target_user_id'=>$estudiante,'event_type'=>'academic.message.sent','module'=>'academic','entity_type'=>'communication_thread','entity_id'=>$hilo,'action'=>'create','result'=>'success','description'=>'Mensaje creado para estudiante relacionado con el curso.'], $pdo);$pdo->commit();try{$html='<div style="font-family:Arial;color:#26342c"><h2 style="color:#4b7f52">Mensaje de tu docente</h2><h3>'.atenea_e($asunto).'</h3><p>'.nl2br(atenea_e($mensaje)).'</p></div>';enviarCorreoAtenea($u['correo'],trim($u['nombre'].' '.$u['apellido']),$asunto,$html,$mensaje,['tipo'=>'mensaje_docente','usuario_id'=>$estudiante,'hilo_id'=>$hilo,'idempotency_key'=>'academico:correo:'.$hilo]);$q=$pdo->prepare('SELECT id,estado FROM correo_envios WHERE idempotency_key=:k');$q->execute(['k'=>'academico:correo:'.$hilo]);$c=$q->fetch();$pdo->prepare('UPDATE comunicacion_mensajes SET correo_envio_id=:c,resultado_envio=:r WHERE id=:id')->execute(['c'=>$c['id']??null,'r'=>($c['estado']??'')==='enviado'?'enviado':'fallido','id'=>$mid]);docenteFlash('exito','Mensaje guardado y enviado.');}catch(Throwable $mailError){$pdo->prepare("UPDATE comunicacion_mensajes SET resultado_envio='fallido' WHERE id=:id")->execute(['id'=>$mid]);registrarErrorSistemaAtenea('correo','comunicacion_docente',sanitizarErrorCorreoAtenea($mailError),['usuario_id'=>$estudiante]);docenteFlash('error','El mensaje quedó guardado, pero el correo no pudo enviarse.');}}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();docenteFlash('error',$e instanceof DomainException?$e->getMessage():'No fue posible guardar el mensaje.');}header('Location:'.docenteUrl('comunicaciones.php',['curso'=>$curso]));
